","stretch":true,"fillArea":true,"textSize":1,"textBackground":"grey","placeholderInvisible":false,"placeholderStretch":true,"placeholderHeight":50,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"imgHeight":300,"imgFit":"inside","imgStretch":true,"hideFigureCaption":false,"hideFigureSubCaption":false,"hideFigureFootnote":false},{"type":"figure","stretch":true,"fillArea":false,"textSize":1,"textBackground":"none","placeholderInvisible":false,"placeholderStretch":true,"placeholderHeight":50,"useFigureAdditionalScale":true,"figureAdditionalScale":1,"imgHeight":300,"imgFit":"inside","imgStretch":true,"hideFigureCaption":false,"hideFigureSubCaption":false,"hideFigureFootnote":false,"presentationObjectInReportInfo":{"id":"c36605cb-474a-44fe-a6b0-cb2a952e7722","moduleId":"m003","isDefault":false,"selectedReplicantValue":""}}]],"useHeader":true,"headerText":"Tendances en soins prénatals","useFooter":false,"footerText":""}}

